mapper.select:
SELECT count(*) FROM hm_query.product_catalog_flat

    product_status = 'PUBLISHED'
    AND product_name LIKE CONCAT('%', #{name}, '%')
    AND brand = #{brand}
    AND category_id = #{categoryId}

SELECT product_id as "id", product_name as "name", description as "description", short_description as "shortDescription", brand as "brand", category_id as "categoryId", category_name as "categoryName", slug as "slug", product_status as "stateId", base_price as "basePrice", avg_rating as "avgRating", review_count as "reviewCount", total_available_qty as "availableQty", stock_status as "stockStatus", seller_name as "sellerName" FROM hm_query.product_catalog_flat
product_status = 'PUBLISHED' AND product_name LIKE CONCAT('%', #{name}, '%') AND brand = #{brand} AND category_id = #{categoryId}
${orderby} ${pagination}

SELECT count(*) FROM hm_query.product_catalog_flat

    AND product_name LIKE CONCAT('%', #{name}, '%')
    AND brand = #{brand}
    AND category_id = #{categoryId}
    AND product_status = #{stateId}
    AND slug = #{slug}
    AND seller_id = #{sellerId}
    AND stock_status = #{stockStatus}
    AND seller_tier = #{sellerTier}
    AND base_price >= #{minPrice}
    AND base_price <= #{maxPrice}
    AND avg_rating >= #{minRating}

SELECT
    product_id       as "id",
    product_name     as "name",
    primary_sku      as "sku",
    brand            as "brand",
    category_id      as "categoryId",
    category_name    as "categoryName",
    slug             as "slug",
    product_status   as "stateId",
    base_price       as "basePrice",
    total_available_qty as "availableQty",
    stock_status     as "stockStatus",
    seller_id        as "sellerId",
    seller_name      as "sellerName",
    seller_tier      as "sellerTier",
    avg_rating       as "avgRating",
    review_count     as "reviewCount",
    violations_count as "violationsCount",
    units_sold_30d   as "unitsSold30d",
    revenue_30d      as "revenue30d",
    conversion_rate  as "conversionRate",
    created_date     as "createdTime"
FROM hm_query.product_catalog_flat

    AND product_name LIKE CONCAT('%', #{name}, '%')
    AND brand = #{brand}
    AND category_id = #{categoryId}
    AND product_status = #{stateId}
    AND slug = #{slug}
    AND seller_id = #{sellerId}
    AND stock_status = #{stockStatus}
    AND seller_tier = #{sellerTier}
    AND base_price >= #{minPrice}
    AND base_price <= #{maxPrice}
    AND avg_rating >= #{minRating}

${orderby} ${pagination}

SELECT count(*) FROM hm_query.product_catalog_flat

    product_status = 'UNDER_REVIEW'
    AND product_name LIKE CONCAT('%', #{name}, '%')
    AND brand = #{brand}
    AND seller_id = #{sellerId}

SELECT product_id as "id", product_name as "name", primary_sku as "sku", brand as "brand", category_name as "categoryName", seller_name as "sellerName", seller_id as "sellerId", created_date as "createdTime" FROM hm_query.product_catalog_flat
product_status = 'UNDER_REVIEW' AND product_name LIKE CONCAT('%', #{name}, '%') AND brand = #{brand} AND seller_id = #{sellerId}
${orderby} ${pagination}

SELECT count(*) FROM hm_query.product_variant_flat pvf
JOIN hm_query.product_catalog_flat pcf ON pvf.product_id = pcf.product_id
WHERE pvf.product_id = #{productId}
  AND pvf.variant_id = #{variantId}
  AND pcf.product_status = 'PUBLISHED'
  AND pvf.available_qty > 0

SELECT count(*) FROM hm_query.category_config_flat

    AND active = #{active}
    AND name LIKE CONCAT('%', #{name}, '%')
    AND parent_id = #{parentId}

SELECT category_id as "id", name as "name", slug as "slug", parent_id as "parentId", path as "path", depth as "depth", active as "active", commission_rate_bps as "commissionRateBps", is_gated as "isGated", return_policy_days as "returnPolicyDays", listing_min_images as "listingMinImages", hsn_code as "hsnCode", gst_rate_pct as "gstRatePct", product_count as "productCount", seller_count as "sellerCount", gmv_30d as "gmv30d" FROM hm_query.category_config_flat
AND active = #{active} AND name LIKE CONCAT('%', #{name}, '%') AND parent_id = #{parentId}
${orderby} ${pagination}

SELECT count(*) FROM hm_query.brand_registry_flat

    AND brand_status = #{brandStatus}
    AND brand_name LIKE CONCAT('%', #{brandName}, '%')
    AND industry_category = #{industryCategory}

SELECT brand_id as "id", brand_name as "brandName", brand_slug as "brandSlug", company_name as "companyName", country_of_origin as "countryOfOrigin", industry_category as "industryCategory", brand_website as "brandWebsite", brand_status as "brandStatus", verified_at as "verifiedAt", created_time as "createdTime", product_count as "productCount", authorized_seller_count as "authorizedSellerCount", trademark_count as "trademarkCount", violation_count as "violationCount", brand_health_score as "brandHealthScore" FROM hm_query.brand_registry_flat
AND brand_status = #{brandStatus} AND brand_name LIKE CONCAT('%', #{brandName}, '%') AND industry_category = #{industryCategory}
${orderby} ${pagination}

SELECT count(*) FROM hm_query.attribute_definition_flat

    AND code LIKE CONCAT('%', #{code}, '%')
    AND label LIKE CONCAT('%', #{label}, '%')
    AND input_type = #{inputType}
    AND filterable = #{filterable}
    AND searchable = #{searchable}

SELECT attribute_id as "id", code as "code", label as "label", input_type as "inputType", filterable as "filterable", searchable as "searchable", required as "required", display_order as "displayOrder", variation_count as "variationCount", product_count as "productCount", category_count as "categoryCount", options_json as "optionsJson", options_count as "optionsCount" FROM hm_query.attribute_definition_flat
AND code LIKE CONCAT('%', #{code}, '%') AND label LIKE CONCAT('%', #{label}, '%') AND input_type = #{inputType} AND filterable = #{filterable} AND searchable = #{searchable}
${orderby} ${pagination}

SELECT set_id as "id", name as "name", attribute_count as "attributeCount", product_count as "productCount", categories_json as "categoriesJson", attributes_json as "attributesJson", created_time as "createdTime" FROM hm_query.attribute_set_flat
AND name LIKE CONCAT('%', #{name}, '%')
${orderby} ${pagination}
